"use client"

import { useHits, useStats, useInstantSearch, useCurrentRefinements, usePagination } from "react-instantsearch"
import { SearchResultsSkeleton } from "./SearchResultsSkeleton"
import { SearchNoResults } from "./SearchNoResults"
import { SearchFilteredNoResults } from "./SearchFilteredNoResults"
import { SearchFilters } from "./SearchFilters"
import { AlgoliaCardHit } from "@/components/cards/AlgoliaCardHit"
import type { AlgoliaHit } from "@/components/cards/AlgoliaCardHit"

// ─── Pagination sub-component ──────────────────────────────────────────────────

function CardPagination() {
  const { currentRefinement, nbPages, nbHits, refine, isFirstPage, isLastPage } = usePagination()
  const hitsPerPage = 20

  if (nbPages <= 1) return null

  const currentPage = currentRefinement // 0-indexed
  const startItem = currentPage * hitsPerPage + 1
  const endItem = Math.min((currentPage + 1) * hitsPerPage, nbHits)

  // Build visible page numbers with ellipsis
  const getVisiblePages = (): (number | "...")[] => {
    const pages: (number | "...")[] = []
    const delta = 2
    const total = nbPages

    pages.push(0) // always first page

    const start = Math.max(1, currentPage - delta)
    const end = Math.min(total - 2, currentPage + delta)

    if (start > 1) pages.push("...")
    for (let i = start; i <= end; i++) pages.push(i)
    if (end < total - 2) pages.push("...")

    if (total > 1) pages.push(total - 1) // always last page

    return pages
  }

  return (
    <div
      data-testid="pagination"
      style={{
        padding: "32px 24px 40px",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        gap: 12,
      }}
    >
      {/* Showing X–Y of Z results */}
      <div
        style={{
          fontSize: 12,
          color: "var(--text-tertiary, #7B72A8)",
        }}
      >
        Showing {startItem.toLocaleString()}–{endItem.toLocaleString()} of{" "}
        {nbHits.toLocaleString()} results
      </div>

      {/* Page buttons */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: 4,
        }}
      >
        {/* Previous arrow */}
        <button
          onClick={() => refine(currentPage - 1)}
          disabled={isFirstPage}
          aria-label="Previous page"
          style={{
            minWidth: 34,
            height: 34,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            borderRadius: 6,
            fontSize: 14,
            fontWeight: 500,
            color: isFirstPage
              ? "var(--border-default, #2C2A4A)"
              : "var(--text-tertiary, #7B72A8)",
            background: "transparent",
            border: "1px solid transparent",
            cursor: isFirstPage ? "default" : "pointer",
            fontFamily: "var(--font-body, 'Inter', sans-serif)",
          }}
        >
          «
        </button>

        {getVisiblePages().map((page, idx) => {
          if (page === "...") {
            return (
              <span
                key={`dots-${idx}`}
                style={{
                  fontSize: 13,
                  color: "var(--text-tertiary, #7B72A8)",
                  padding: "0 4px",
                }}
              >
                …
              </span>
            )
          }

          const isActive = page === currentPage

          return (
            <button
              key={page}
              onClick={() => refine(page)}
              aria-label={`Page ${page + 1}`}
              aria-current={isActive ? "page" : undefined}
              style={{
                minWidth: 34,
                height: 34,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                borderRadius: 6,
                fontSize: 13,
                fontWeight: isActive ? 600 : 500,
                color: isActive ? "#fff" : "var(--text-secondary, #B8B0D8)",
                background: isActive
                  ? "var(--brand-primary, #8B5CF6)"
                  : "transparent",
                border: isActive
                  ? "1px solid var(--brand-primary, #8B5CF6)"
                  : "1px solid transparent",
                cursor: "pointer",
                fontFamily: "var(--font-body, 'Inter', sans-serif)",
              }}
            >
              {page + 1}
            </button>
          )
        })}

        {/* Next arrow */}
        <button
          onClick={() => refine(currentPage + 1)}
          disabled={isLastPage}
          aria-label="Next page"
          style={{
            minWidth: 34,
            height: 34,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            borderRadius: 6,
            fontSize: 14,
            fontWeight: 500,
            color: isLastPage
              ? "var(--border-default, #2C2A4A)"
              : "var(--text-tertiary, #7B72A8)",
            background: "transparent",
            border: "1px solid transparent",
            cursor: isLastPage ? "default" : "pointer",
            fontFamily: "var(--font-body, 'Inter', sans-serif)",
          }}
        >
          »
        </button>
      </div>
    </div>
  )
}

// ─── CardSearchGrid ────────────────────────────────────────────────────────────

/**
 * Shared sidebar + card grid layout with numbered pagination.
 * Renders the SearchFilters sidebar (280px) and the card hit grid (flex-1).
 * Used by both CardBrowsingPage and the search page.
 */
export function CardSearchGrid() {
  const { items: hits } = useHits<AlgoliaHit>()
  const { nbHits, query } = useStats()
  const { status, results } = useInstantSearch()
  const { items: refinementItems } = useCurrentRefinements()

  const activeFilterCount = refinementItems.reduce((sum, item) => sum + item.refinements.length, 0)
  const hasActiveFilters = activeFilterCount > 0

  const isLoading = status === "loading" || status === "stalled"
  const isInitialLoading = isLoading && hits.length === 0
  const isNoResults = !isLoading && nbHits === 0

  return (
    <div
      data-testid="card-search-grid"
      style={{ display: "flex", minHeight: 900 }}
    >
      {/* Desktop sidebar — always mounted, hidden on mobile via SearchFilters internal responsive logic */}
      <SearchFilters activeFilterCount={activeFilterCount} />

      {/* Main content */}
      <div style={{ flex: 1, minWidth: 0, padding: "20px 24px" }}>
        {isInitialLoading ? (
          <SearchResultsSkeleton />
        ) : isNoResults ? (
          hasActiveFilters ? (
            <SearchFilteredNoResults
              onClearFilters={() => {
                setTimeout(() => {
                  for (const item of refinementItems) {
                    for (const refinement of item.refinements) {
                      item.refine(refinement)
                    }
                  }
                }, 0)
              }}
            />
          ) : (
            <SearchNoResults query={query} queryAfterRemoval={results?.queryAfterRemoval} />
          )
        ) : (
          <>
            {/* Card grid — 4-col → 3 @ 1024px → 2 @ 640px */}
            <div
              data-testid="card-grid"
              className="grid gap-4"
              style={{
                gridTemplateColumns: "repeat(4, 1fr)",
              }}
            >
              <style>{`
                @media (max-width: 1024px) {
                  [data-testid="card-grid"] { grid-template-columns: repeat(3, 1fr) !important; }
                }
                @media (max-width: 640px) {
                  [data-testid="card-grid"] {
                    grid-template-columns: repeat(2, 1fr) !important;
                    gap: 10px !important;
                    padding: 0 12px;
                  }
                }
              `}</style>
              {hits.map((hit) => (
                <AlgoliaCardHit key={hit.objectID} hit={hit} />
              ))}
            </div>

            {/* Numbered pagination */}
            <CardPagination />
          </>
        )}
      </div>
    </div>
  )
}

"use client"

import { useState, useEffect } from "react"
import { useStats, useSearchBox, Configure } from "react-instantsearch"
import { InstantSearchNext } from "react-instantsearch-nextjs"
import { UiState } from "instantsearch.js"
import { algoliaClient, CARDS_INDEX, CARDS_INDEX_PRICE_ASC, CARDS_INDEX_PRICE_DESC } from "@/lib/algolia"
import { ActiveFilterChips } from "./ActiveFilterChips"
import { SortControl } from "./SortControl"
import { CardSearchGrid } from "./CardSearchGrid"

// ─── URL state mapping ────────────────────────────────────────────────────────

const SORT_TO_PARAM: Record<string, string> = {
  [CARDS_INDEX]:           "relevance",
  [CARDS_INDEX_PRICE_ASC]: "price-asc",
  [CARDS_INDEX_PRICE_DESC]:"price-desc",
}
const PARAM_TO_SORT: Record<string, string> = Object.fromEntries(
  Object.entries(SORT_TO_PARAM).map(([k, v]) => [v, k])
)

export function createCardsStateMapping() {
  return {
    stateToRoute(uiState: UiState): Record<string, unknown> {
      const idx = uiState[CARDS_INDEX] ?? {}
      const route: Record<string, unknown> = {}
      if (idx.query)        route.q        = idx.query
      const facets = idx.refinementList ?? {}
      if (facets.game?.length)      route.game      = facets.game
      if (facets.rarity?.length)    route.rarity    = facets.rarity
      if (facets.condition?.length) route.condition = facets.condition
      if (facets.set_name?.length)  route.set       = facets.set_name
      if (facets.language?.length)  route.language  = facets.language
      const numeric = idx.numericMenu ?? {}
      if (numeric.lowest_price)     route.price     = numeric.lowest_price
      if (idx.sortBy && idx.sortBy !== CARDS_INDEX) {
        route.sort = SORT_TO_PARAM[idx.sortBy] ?? idx.sortBy
      }
      if (idx.page && idx.page > 0) {
        route.page = idx.page + 1 // URL is 1-indexed, Algolia is 0-indexed
      }
      return route
    },
    routeToState(routeState: Record<string, unknown>): UiState {
      const toArr = (v: unknown): string[] => v ? [v].flat() as string[] : []
      const refinementList: Record<string, string[]> = {
        game:      toArr(routeState.game),
        rarity:    toArr(routeState.rarity),
        condition: toArr(routeState.condition),
        set_name:  toArr(routeState.set),
        language:  toArr(routeState.language),
      }
      const pageParam = routeState.page ? Number(routeState.page) : undefined
      return {
        [CARDS_INDEX]: {
          query:          (routeState.q as string) ?? "",
          refinementList,
          numericMenu:    routeState.price ? { lowest_price: routeState.price as string } : undefined,
          sortBy:         routeState.sort ? (PARAM_TO_SORT[routeState.sort as string] ?? undefined) : undefined,
          page:           pageParam && pageParam > 1 ? pageParam - 1 : undefined, // URL is 1-indexed, Algolia is 0-indexed
        },
      }
    },
  }
}

// ─── Inline search bar ────────────────────────────────────────────────────────

function SearchBar() {
  const { query, refine } = useSearchBox()
  const [inputValue, setInputValue] = useState(query)

  useEffect(() => { setInputValue(query) }, [query])

  return (
    <div className="mb-4">
      <input
        type="search"
        value={inputValue}
        onChange={(e) => {
          setInputValue(e.target.value)
          setTimeout(() => refine(e.target.value), 0)
        }}
        placeholder="Search cards by name, set, or artist…"
        className="w-full rounded-2xl px-5 py-3 text-sm"
        style={{
          border: "1px solid var(--border)",
          background: "rgba(24, 22, 42, 0.60)",
          backdropFilter: "blur(12px)",
          color: "var(--text-primary, #F0EEFF)",
          outline: "none",
        }}
      />
    </div>
  )
}

// ─── Results body (inside InstantSearchNext context) ──────────────────────────

function ResultsBody({ initialQuery }: { initialQuery: string }) {
  const { nbHits, query } = useStats()
  const isLoading = false // Lightweight — actual loading state is in CardSearchGrid

  return (
    <>
      {/* Inline search bar — full width above chips+sort row */}
      <SearchBar />

      {/* Result count — above chips row */}
      {query && (
        <p className="text-[13px] mb-2 text-secondary">
          <span className="font-semibold text-primary">
            {nbHits.toLocaleString()}
          </span>{" "}results for &quot;{query}&quot;
        </p>
      )}

      {/* Filter chips + sort — same full-width row, above sidebar+grid */}
      <div className="flex items-center gap-2 mb-4 min-w-0">
        <div className="flex-1 min-w-0">
          <ActiveFilterChips />
        </div>
        <div className="hidden md:block flex-shrink-0 ml-auto">
          <SortControl />
        </div>
      </div>

      {/* Shared sidebar+grid layout */}
      <CardSearchGrid />
    </>
  )
}

// ─── Public component ─────────────────────────────────────────────────────────

interface AlgoliaSearchResultsProps {
  initialQuery: string
  initialGame?: string
}

export function AlgoliaSearchResults({ initialQuery, initialGame }: AlgoliaSearchResultsProps) {
  return (
    <InstantSearchNext
      searchClient={algoliaClient}
      indexName={CARDS_INDEX}
      routing={{ stateMapping: createCardsStateMapping() }}
      initialUiState={{ [CARDS_INDEX]: { query: initialQuery, refinementList: { game: initialGame ? [initialGame] : [], rarity: [], condition: [], set_name: [], language: [] } } }}
    >
      <Configure hitsPerPage={20} />
      <ResultsBody initialQuery={initialQuery} />
    </InstantSearchNext>
  )
}

"use client"

import Link from "next/link"
import { Highlight } from "react-instantsearch"
import type { Hit } from "instantsearch.js"

// ─── Game dot colors (matching GameBadge tokens) ───────────────────────────────

const GAME_DOT_COLORS: Record<string, string> = {
  MTG: "var(--game-mtg)",
  POKEMON: "var(--game-pokemon)",
  YUGIOH: "var(--game-yugioh)",
  OPTCG: "var(--game-optcg)",
}

const GAME_SHORT_LABELS: Record<string, string> = {
  MTG: "MTG",
  POKEMON: "PKM",
  YUGIOH: "YGO",
  OPTCG: "OP",
}

// ─── Condition badge colors (matching wireframe) ───────────────────────────────

const CONDITION_STYLES: Record<string, { bg: string; color: string }> = {
  NM: { bg: "rgba(16, 185, 129, 0.12)", color: "var(--positive, #10B981)" },
  LP: { bg: "rgba(245, 158, 11, 0.12)", color: "var(--warning, #F59E0B)" },
  MP: { bg: "rgba(255, 120, 73, 0.12)", color: "var(--brand-secondary, #FF7849)" },
  HP: { bg: "rgba(239, 68, 68, 0.12)", color: "var(--negative, #EF4444)" },
  DMG: { bg: "rgba(255, 120, 73, 0.12)", color: "var(--brand-secondary, #FF7849)" },
}

// ─── Types ─────────────────────────────────────────────────────────────────────

export type AlgoliaHit = Hit<{
  name: string
  set_name: string
  set_code: string
  game: string
  rarity: string | null
  image_url: string | null
  lowest_price: number | null
  seller_count: number
  card_id: string
  condition?: string | null
  seller_name?: string | null
  seller_rating?: number | null
}>

// ─── Price formatter ───────────────────────────────────────────────────────────

function formatPrice(price: number): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    minimumFractionDigits: 2,
  }).format(price)
}

// ─── Star rating ───────────────────────────────────────────────────────────────

function StarRating({ rating }: { rating: number }) {
  const stars = []
  for (let i = 1; i <= 5; i++) {
    stars.push(i <= rating ? "★" : "☆")
  }
  return (
    <span
      aria-label={`${rating} out of 5 stars`}
      style={{
        fontSize: 10,
        color: "var(--warning, #F59E0B)",
        letterSpacing: 1,
      }}
    >
      {stars.join("")}
    </span>
  )
}

// ─── AlgoliaCardHit ────────────────────────────────────────────────────────────

export function AlgoliaCardHit({ hit }: { hit: AlgoliaHit }) {
  const gameCode = hit.game?.toUpperCase() ?? ""
  const dotColor = GAME_DOT_COLORS[gameCode] ?? "var(--text-tertiary)"
  const gameLabel = GAME_SHORT_LABELS[gameCode] ?? gameCode.slice(0, 3)
  const condition = hit.condition?.toUpperCase() ?? null
  const conditionStyle = condition ? CONDITION_STYLES[condition] ?? null : null

  return (
    <Link
      href={`/cards/${hit.card_id}`}
      className="group block"
      data-testid="card-hit"
      style={{
        background: "var(--bg-surface-1, #18162A)",
        border: "1px solid var(--border-default, #2C2A4A)",
        borderRadius: 14,
        padding: 12,
        transition: "border-color 0.15s, box-shadow 0.15s",
        textDecoration: "none",
        color: "inherit",
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.borderColor = "var(--border-strong, #4A4680)"
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.borderColor = "var(--border-default, #2C2A4A)"
      }}
    >
      {/* Card image with game indicator overlay */}
      <div
        style={{
          width: "100%",
          aspectRatio: "5 / 7",
          background: "var(--bg-surface-3, #2C2A4A)",
          borderRadius: 10,
          marginBottom: 10,
          border: "1px solid var(--border-default, #2C2A4A)",
          position: "relative",
          overflow: "hidden",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        {hit.image_url ? (
          <img
            src={hit.image_url}
            alt={hit.name}
            className="w-full h-full object-cover [@media(pointer:fine)]:group-hover:scale-105 transition-transform"
          />
        ) : (
          <span
            style={{
              fontSize: 10,
              color: "var(--text-tertiary, #7B72A8)",
              textAlign: "center",
              padding: 4,
            }}
          >
            No image
          </span>
        )}
        {/* Game indicator dot + text (top-left pill) */}
        <div
          style={{
            position: "absolute",
            top: 6,
            left: 6,
            display: "flex",
            alignItems: "center",
            gap: 4,
            background: "rgba(9, 9, 15, 0.75)",
            backdropFilter: "blur(4px)",
            padding: "2px 7px",
            borderRadius: 20,
            fontSize: 9,
            fontWeight: 600,
          }}
        >
          <span
            style={{
              width: 6,
              height: 6,
              borderRadius: "50%",
              background: dotColor,
              display: "inline-block",
              flexShrink: 0,
            }}
          />
          <span style={{ color: dotColor }}>{gameLabel}</span>
        </div>
      </div>

      {/* Card details */}
      <div style={{ padding: "0 2px" }}>
        {/* Card name */}
        <p
          style={{
            fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
            fontSize: 14,
            fontWeight: 600,
            color: "var(--text-primary, #F0EEFF)",
            whiteSpace: "nowrap",
            overflow: "hidden",
            textOverflow: "ellipsis",
            marginBottom: 2,
            lineHeight: 1.3,
          }}
        >
          <Highlight attribute="name" hit={hit} />
        </p>

        {/* Set name */}
        <p
          style={{
            fontSize: 12,
            color: "var(--text-secondary, #B8B0D8)",
            marginBottom: 6,
            whiteSpace: "nowrap",
            overflow: "hidden",
            textOverflow: "ellipsis",
          }}
        >
          {hit.set_name}
        </p>

        {/* Condition badge + price row */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            marginBottom: 6,
          }}
        >
          {conditionStyle ? (
            <span
              data-testid="condition-badge"
              style={{
                fontSize: 10,
                fontWeight: 600,
                padding: "2px 8px",
                borderRadius: 20,
                background: conditionStyle.bg,
                color: conditionStyle.color,
              }}
            >
              {condition}
            </span>
          ) : (
            <span />
          )}
          <span
            style={{
              fontFamily: "var(--font-mono, 'DM Mono', monospace)",
              fontSize: 16,
              fontWeight: 500,
              color: "var(--brand-primary, #8B5CF6)",
            }}
          >
            {hit.lowest_price != null ? formatPrice(hit.lowest_price) : "—"}
          </span>
        </div>

        {/* Seller name + stars */}
        {hit.seller_name && (
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 6,
              marginTop: 6,
            }}
          >
            <span
              style={{
                fontSize: 11,
                color: "var(--text-tertiary, #7B72A8)",
              }}
            >
              {hit.seller_name}
            </span>
            {hit.seller_rating != null && (
              <StarRating rating={hit.seller_rating} />
            )}
          </div>
        )}

        {/* Add to Cart button */}
        <button
          data-testid="add-to-cart-btn"
          onClick={(e) => {
            e.preventDefault()
            e.stopPropagation()
            // Cart integration will be wired in a future slice
          }}
          style={{
            width: "100%",
            height: 32,
            marginTop: 8,
            background: "var(--bg-surface-2, #21203A)",
            border: "1px solid var(--border-default, #2C2A4A)",
            borderRadius: 6,
            color: "var(--text-secondary, #B8B0D8)",
            fontFamily: "var(--font-body, 'Inter', sans-serif)",
            fontSize: 12,
            fontWeight: 500,
            cursor: "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            gap: 4,
          }}
        >
          + Add to Cart
        </button>
      </div>
    </Link>
  )
}

"use client"

interface Props {
  count?: number
}

/**
 * Skeleton loading cards matching the wireframe pattern:
 * dashed border-strong border, skeleton-pulse linear gradient sweep,
 * 5:7 image placeholder, 3 text lines (full, 80%, 60%).
 */
export function CardGridSkeleton({ count = 8 }: Props) {
  return (
    <>
      <style>{`
        @keyframes skeleton-pulse {
          0% { background-position: 200% 0; }
          100% { background-position: -200% 0; }
        }
        .sd-skeleton-shimmer {
          background: linear-gradient(
            90deg,
            var(--bg-surface-2, #21203A) 25%,
            var(--bg-surface-3, #2C2A4A) 50%,
            var(--bg-surface-2, #21203A) 75%
          );
          background-size: 400% 100%;
          animation: skeleton-pulse 1.8s ease-in-out infinite;
        }
      `}</style>
      <div
        data-testid="card-grid-skeleton"
        className="grid gap-4"
        style={{ gridTemplateColumns: "repeat(4, 1fr)" }}
      >
        <style>{`
          @media (max-width: 1024px) {
            [data-testid="card-grid-skeleton"] { grid-template-columns: repeat(3, 1fr) !important; }
          }
          @media (max-width: 640px) {
            [data-testid="card-grid-skeleton"] {
              grid-template-columns: repeat(2, 1fr) !important;
              gap: 10px !important;
            }
          }
        `}</style>
        {Array.from({ length: count }).map((_, i) => (
          <div
            key={i}
            data-testid="skeleton-card"
            style={{
              background: "var(--bg-surface-1, #18162A)",
              border: "1px dashed var(--border-strong, #4A4680)",
              borderRadius: 14,
              padding: 12,
            }}
          >
            {/* Image placeholder — 5:7 aspect */}
            <div
              className="sd-skeleton-shimmer"
              style={{
                width: "100%",
                aspectRatio: "5 / 7",
                borderRadius: 10,
                marginBottom: 10,
              }}
            />
            {/* Text line 1 — full width */}
            <div
              className="sd-skeleton-shimmer"
              style={{
                height: 12,
                borderRadius: 4,
                marginBottom: 8,
                width: "100%",
              }}
            />
            {/* Text line 2 — 80% width */}
            <div
              className="sd-skeleton-shimmer"
              style={{
                height: 12,
                borderRadius: 4,
                marginBottom: 8,
                width: "80%",
              }}
            />
            {/* Text line 3 — 60% width */}
            <div
              className="sd-skeleton-shimmer"
              style={{
                height: 12,
                borderRadius: 4,
                width: "60%",
              }}
            />
          </div>
