import { InstantSearchNext } from "react-instantsearch-nextjs"
import { algoliaClient, CARDS_INDEX } from "@/lib/algolia"
import { createCardsStateMapping } from "@/components/search/AlgoliaSearchResults"
import { CardSearchGrid } from "@/components/search/CardSearchGrid"
import { BrowseBreadcrumbs } from "./BrowseBreadcrumbs"
import { GameSelectorStrip } from "./GameSelectorStrip"
import { CategoryPills } from "./CategoryPills"
import { PopularSetsCarousel } from "./PopularSetsCarousel"
import { ResultsBar } from "./ResultsBar"
import { BrowsePageGameTracker } from "./BrowsePageGameTracker"
import { TrendingStrip, TRENDING_PLACEHOLDER } from "./TrendingStrip"
import { SellerCTA } from "./SellerCTA"

interface Props {
  initialQuery?: string
  initialGame?: string
}

export function CardBrowsingPage({ initialQuery, initialGame }: Props) {
  return (
    <InstantSearchNext
      searchClient={algoliaClient}
      indexName={CARDS_INDEX}
      routing={{ stateMapping: createCardsStateMapping() }}
      initialUiState={{
        [CARDS_INDEX]: {
          query: initialQuery ?? "",
          refinementList: {
            game: initialGame ? [initialGame] : [],
            rarity: [],
            condition: [],
            set_name: [],
            language: [],
          },
        },
      }}
    >
      <Configure hitsPerPage={20} />
      <BrowsePageContent initialGame={initialGame ?? null} />
    </InstantSearchNext>
  )
}

// ─── Inner content (needs InstantSearch context) ───────────────────────────────

function BrowsePageContent({ initialGame }: { initialGame: string | null }) {
  const [activeGame, setActiveGame] = useState<string | null>(initialGame)

  return (
    <div>
      {/* Breadcrumbs */}
      <BrowseBreadcrumbs />

      {/* Game Selector Strip */}
      <GameSelectorStrip />

      {/* Track active game for child components */}
      <BrowsePageGameTracker onGameChange={setActiveGame} />

      {/* Category Quick Links — hidden on mobile */}
      <div className="hidden md:block">
        <CategoryPills />
      </div>

      {/* Popular Sets Carousel — hidden on mobile */}
      <div className="hidden md:block">
        <PopularSetsCarousel gameCode={activeGame} />
      </div>

      {/* Results Bar */}
      <ResultsBar />

      {/* Sidebar + Grid with pagination */}
      <CardSearchGrid />

      {/* Trending Cards section */}
      <TrendingStrip cards={TRENDING_PLACEHOLDER} />

      {/* Seller CTA Banner */}
      <SellerCTA />
    </div>
  )
}

